    # Checking diagonals
    for k in range(2 * n - 1):
        diagonal1 = [0, 0, 0]
        diagonal2 = [0, 0, 0]
        for i in range(n):
            for j in range(n):
                if i + j == k:
                    cell_value = (i + j) % 3
                    if cell_value == 0:
                        diagonal1[0] += 1
                    elif cell_value == 1:
                        diagonal1[1] += 1
                    else:
                        diagonal1[2] += 1
                if i - j == k - n:
                    cell_value = (i - j) % 3
                    if cell_value == 0:
                        diagonal2[0] += 1
                    elif cell_value == 1:
                        diagonal2[1] += 1
                    else:
                        diagonal2[2] += 1
        if k % 3 == 0 and (diagonal1[0] != diagonal1[1] or diagonal1[1] != diagonal1[2]):
            return False
        if (k - n) % 3 == 0 and (diagonal2[0] != diagonal2[1] or diagonal2[1] != diagonal2[2]):
            return False

    return True

